<div class="page-title-row"><div><span class="text-muted">Platform</span><h1>Modules</h1><p class="text-muted mb-0">Manage the platform areas that appear in this installation. Core remains mandatory because deleting the floor is rarely helpful.</p></div></div>
<div class="row g-4"><?php foreach($modules as $key=>$module):?><div class="col-md-6 col-xl-4"><div class="portal-card p-4 h-100"><div class="d-flex justify-content-between"><div><h2 class="h5 mb-1"><?=e($module['name'])?></h2><div class="text-muted small">Version <?=e($module['version'])?></div></div><span class="badge text-bg-<?=$module['enabled']?'success':'secondary'?>"><?=$module['enabled']?'Enabled':'Disabled'?></span></div><form method="post" action="/portal/modules" class="mt-4"><?=csrf_field()?><input type="hidden" name="module_key" value="<?=e($key)?>"><div class="form-check form-switch"><input class="form-check-input" type="checkbox" name="enabled" value="1" id="mod-<?=e($key)?>" <?=$module['enabled']?'checked':''?> <?=$key==='core'?'disabled':''?>><label class="form-check-label" for="mod-<?=e($key)?>">Available to this installation</label></div><?php if($key==='core'):?><input type="hidden" name="enabled" value="1"><?php endif?><button class="btn btn-outline-primary btn-sm mt-3">Save</button></form></div></div><?php endforeach?></div>
